If  belongs to , then we try to improve the value of : .
Since  is already in , we don't need to insert it into  and the queue.
If  belongs to , and if  can be improved , then we improve  and insert the vertex  back to the set , placing it at the beginning of the queue.

And of course, with each update in the array  we also have to update the corresponding element in the array .
Implementation
We will use an array  to store in which set each vertex is currently.
struct Edge {
    int to, w;
};

int n;
vector<vector<Edge>> adj;

const int INF = 1e9;

void shortest_paths(int v0, vector<int>& d, vector<int>& p) {
    d.assign(n, INF);
    d[v0] = 0;
    vector<int> m(n, 2);
    deque<int> q;
    q.push_back(v0);
    p.assign(n, -1);

    while (!q.empty()) {
        int u = q.front();
        q.pop_front();
        m[u] = 0;
        for (Edge e : adj[u]) {
            if (d[e.to] > d[u] + e.w) {
                d[e.to] = d[u] + e.w;
                p[e.to] = u;
                if (m[e.to] == 2) {
                    m[e.to] = 1;
                    q.push_back(e.to);
                } else if (m[e.to] == 0) {
                    m[e.to] = 1;
                    q.push_front(e.to);
                }
            }
        }
    }
}

Complexity
The algorithm usually performs quite fast - in most cases, even faster than Dijkstra's algorithm.
However there exist cases for which the algorithm takes exponential time, making it unsuitable in the worst-case. See discussions on Stack Overflow and Codeforces for reference.

