    l[0]=-1;
    r[0]=-1;
    l[1]=-1;
    r[1]=-1;
    memset (t, -1, sizeof t);
    fill(t[1],t[1]+26,0);
    // add the text to the tree, letter by letter
    for (la=0; la<(int)a.size(); ++la)
        ukkadd (a[la]-'a');
}

vector<int> z_function_trivial(string s) {
    int n = s.size();
    vector<int> z(n);
    for (int i = 1; i < n; i++) {
        while (i + z[i] < n && s[z[i]] == s[i + z[i]]) {
            z[i]++;
        }
    }
    return z;
}

vector<int> z_function(string s) {
    int n = s.size();
    vector<int> z(n);
    int l = 0, r = 0;
    for(int i = 1; i < n; i++) {
        if(i < r) {
            z[i] = min(r - i, z[i - l]);
        }
        while(i + z[i] < n && s[z[i]] == s[i + z[i]]) {
            z[i]++;
        }
        if(i + z[i] > r) {
            l = i;
            r = i + z[i];
        }
    }
    return z;
}

theory:
Monotonic Stack - Algorithms for Competitive Programming

Monotonic Stack
A monotonic stack is a stack data structure that maintains its elements in either increasing or decreasing order. It is commonly used to solve problems involving nearest greater/smaller elements, range contributions, and linear-time array processing.

There are two common variants:
1. Increasing Monotonic Stack
2. Decreasing Monotonic Stack

A decreasing monotonic stack is commonly used for problems like Next Greater Element, Daily Temperatures, and Stock Span.

Consider the implementation:

stack<int> st;
vector<int> ans(n, -1);

for (int i = n - 1; i >= 0; i--) {
    while (!st.empty() && st.top() <= arr[i]) {
        st.pop();
    }

    if (!st.empty()) {
        ans[i] = st.top();
    }

    st.push(arr[i]);
}

Why does this work?
When processing arr[i], smaller or equal elements are removed since they can never become the next greater element for future positions.

Each element is pushed and popped at most once.
Therefore the total complexity is O(n).

Applications
- Daily Temperatures
- Next Greater Element
- Previous Greater Element
- Largest Rectangle in Histogram
- Trapping Rain Water
- Stock Span Problem
- Sliding Window Maximum

Monotonic stacks are especially useful for problems involving nearest greater/smaller elements and stack-based linear traversals.

